"use strict";(()=>{var t=class{add(m,r){return m+r}subtract(m,r){return m-r}};var d=new t,n=document.getElementById("num1"),u=document.getElementById("num2"),s=document.getElementById("result");document.getElementById("addBtn")?.addEventListener("click",()=>{if(n&&u){let e=d.add(Number(n.value),Number(u.value));s.innerText=`Result: ${e}`}});document.getElementById("subBtn")?.addEventListener("click",()=>{if(n&&u){let e=d.subtract(Number(n.value),Number(u.value));s.innerText=`Result: ${e}`}});})();
